/// <summary>
/// ///    changes for closing ctock report
/// Developed by SD S3
/// </summary>
[
    SRSReportParameterAttribute(classStr(ETG_ClosingStockValContract))
    ]
    class ETG_ClosingStockValDP extends SrsReportDataProviderPreProcessTempDB
{
    ETG_ClosingStockValContract         ETG_ClosingStockValContract;

    ETG_ClosingStockValLedgerLine     closingStockValLedgerLine;
    TransDate                           _tdate;
    DateOnhand                          _from;
    InventTable                         inventTable;
    InventTrans                         inventtrans,inventtrans1;
    InventTransOrigin                   inventTransOrigin;
    InventDim                           inventDim;
    InventDim                           inventDimTot;
    InventItemGroup                     inventItemGroup;
    InventItemGroupItem                 inventItemGroupItem;
    ItemId                              _itemid,s3itemid;
    InventDimId                         inventdimid,s3inventdimid;
    InventDim                           inventDimLocal;
    CompanyInfo                         companyInfo;
    InventValueReportTmpLine            inventValueReportTmpLine;
    NoYes                               config,size,color,style,site , warehouse,location,batchnumber,serialNumber;
    real                                purchqty, soldqty, soldamount, purchamount, deductedqty, deductedamount, receivedqty, receivedamount;             //rajesh
    ETGACFParameters                    acfParameters = ETGACFParameters::find();
    PurchLine                           purchLine, purchLine1;
    VendTable                           vendTable;
    PurchTable                          purchTable;
    VendInvoiceTrans                    vendInvoiceTrans;
    VendInvoiceJour                     vendInvoiceJour;
    AgreementLine                       agreementLine;
    VendBankAccount                     vendBankAccount;
    AgreementHeader                     agreementHeader;
    PurchAgreementHeader                purchAgreementHeader;
    InventDim                           inventDim1;



}

